import React, { Component } from "react";
import { motion } from "framer-motion";

class About extends Component {
  render() {
    if (this.props.resumeBasicInfo) {
      var sectionName = this.props.resumeBasicInfo.section_name.about;
      var hello = this.props.resumeBasicInfo.description_header;
      var about = this.props.resumeBasicInfo.description;
    }

    return (
      <motion.section
        id="about"
        initial={{ opacity: 0, y: 50 }}
        animate={{ opacity: 1, y: 0 }}   // ✅ changed
        transition={{ duration: 0.6 }}
      >
        <div className="col-md-12">

          {/* Section Title */}
          <h1 style={{ color: "black", textAlign: "center" }}>
            <span>{sectionName}</span>
          </h1>

          <div className="row center mx-auto mb-5">
            <div className="col-md-8 mx-auto">

              <motion.div
                className="card"
                initial={{ opacity: 0, y: 30 }}
                animate={{ opacity: 1, y: 0 }}   // ✅ changed
                transition={{ duration: 0.5, delay: 0.2 }}
                whileHover={{ scale: 1.02 }}
              >

                <div className="card-header">
                  <span className="iconify" data-icon="emojione:red-circle"></span>
                  &nbsp;
                  <span className="iconify" data-icon="twemoji:yellow-circle"></span>
                  &nbsp;
                  <span className="iconify" data-icon="twemoji:green-circle"></span>
                </div>

                <div
                  className="card-body font-trebuchet text-justify ml-3 mr-3"
                  style={{
                    height: "auto",
                    fontSize: "132%",
                    lineHeight: "200%",
                    paddingBottom: "40px"
                  }}
                >
                  <br />
                  <span className="wave">{hello} :)</span>
                  <br />
                  <br />
                  {about}
                </div>

              </motion.div>

            </div>
          </div>

        </div>
      </motion.section>
    );
  }
}

export default About;
